mapper.select:
      
      SELECT * FROM (
         SELECT ROWNUM AS RNUM, list.* FROM (
            SELECT * FROM bnc_document document 
      
	      
	         
	         WHERE document.${searchType} like '%'||#{searchKeyword}||'%'
	         
	      
	      order by doct_code DESC
      
         ) list
      )
      
      
      
      WHERE RNUM > #{startRowNumber} AND RNUM <= #{endRowNumber}

mapper.update:
update bnc_document set 
	doct_code = #{doct_code}, 
	doct_name = #{doct_name}, 
	doct_form = #{doct_form}
	WHERE doct_code = #{doct_code}
